// The ROUGH isometric-hold reference dataset (dead hang, plank), loaded onto the
// curated-dataset framework (issue #1135). Copies the fitness-norms.ts / strength-
// standards.ts shape: import the envelope JSON (generated by
// scripts/gen-fitness-hold-norms.ts), validate it once with loadDataset(), and expose the
// hold ENTRIES + a name→HoldNormEntry map the pure lookup consumes. Identity is the
// battery test key `name` ("deadhang"/"plank", nameStrategy). The registry lists this for
// the linter; lib/fitness-hold-norms.ts is the pure band lookup over these entries.
// Pure — no DB, no network.

import rawHoldNorms from "./data/fitness-hold-norms.json";
import { loadDataset } from "./loader";
import { nameStrategy } from "./matcher";
import type { HoldNormEntry } from "@/scripts/gen-fitness-hold-norms";

export type {
  HoldNormEntry,
  HoldSexLadder,
  HoldBand,
  HoldNormQuality,
} from "@/scripts/gen-fitness-hold-norms";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const fitnessHoldNormsDataset = loadDataset<HoldNormEntry>(rawHoldNorms);

// Identity strategy: the battery test key `name` (case-folded). For the linter/harness.
export const fitnessHoldNormNameStrategy = nameStrategy;

// The hold entries (curated order) the pure lookup consumes.
export const FITNESS_HOLD_NORM_ENTRIES: HoldNormEntry[] =
  fitnessHoldNormsDataset.entries;

// A name→HoldNormEntry map keyed by the EXACT test key (byte-for-byte). One source of
// truth for the pure lookup's `HOLDS[name]`.
export const FITNESS_HOLD_NORMS_MAP: Record<string, HoldNormEntry> =
  Object.fromEntries(FITNESS_HOLD_NORM_ENTRIES.map((e) => [e.name, e]));

// The dataset's single citation source (the disclosure surfaces render from data).
export const FITNESS_HOLD_NORMS_CITATION =
  fitnessHoldNormsDataset.citation[0]?.source ?? "";
